/**
 * kigu-quant Demo — Rosito Bench
 * Tiny tools. Big solutions.
 *
 * Demonstrates LUT and CORDIC sin evaluation on embedded hardware.
 * Headers generated by kigu-quant — no FPU, no libm, no dependencies.
 *
 * Compatible: ESP32, ESP8266, Arduino + Ethernet/WiFi shield
 *
 * ESP32 / ESP8266:
 *   - Set WIFI_SSID and WIFI_PASSWORD below
 *   - Open Serial Monitor at 115200 to get the IP address
 *   - Open browser: http://<ip>/
 *
 * Board: ESP32-C3 Super Mini (tested)
 */

#include <Arduino.h>

// ── WiFi ──────────────────────────────────────────────────────────────────────
#if defined(ESP32) || defined(ARDUINO_ARCH_ESP32)
  #include <WiFi.h>
  #include <WebServer.h>
  WebServer server(80);
#elif defined(ESP8266) || defined(ARDUINO_ARCH_ESP8266)
  #include <ESP8266WiFi.h>
  #include <ESP8266WebServer.h>
  ESP8266WebServer server(80);
#else
  #error "Unsupported board: this sketch requires ESP32 or ESP8266"
#endif

const char* WIFI_SSID     = "your-ssid";
const char* WIFI_PASSWORD = "your-password";

// ── kigu-quant generated headers ─────────────────────────────────────────────
#include "lut_sin.h"      // LUT backend,   256 points, Q1.15
#include "cordic_sin.h"   // CORDIC backend, 16 iters,  Q1.15

// ── Evaluate both at N points and return as JSON ─────────────────────────────
#define DEMO_POINTS 128

String build_json() {
  String json = "{\"labels\":[";

  // X axis: 0..2pi over DEMO_POINTS
  for (int i = 1; i < DEMO_POINTS; i++) {
    float x = (float)i / (DEMO_POINTS ) * 6.2831853f;
    json += String(x, 4);
    if (i < DEMO_POINTS - 1) json += ",";
  }
  json += "],\"lut\":[";

  for (int i = 1; i < DEMO_POINTS; i++) {
    float x = (float)i / (DEMO_POINTS ) * 6.2831853f;
    float v = lut_sin_lookup(x);
    json += String(v, 5);
    if (i < DEMO_POINTS - 1) json += ",";
  }
  json += "],\"cordic\":[";

  for (int i = 1; i < DEMO_POINTS; i++) {
    float x = (float)i / (DEMO_POINTS ) * 6.2831853f;
    float v  = cordic_sin_lookup(x);
    json += String(v, 5);
    if (i < DEMO_POINTS - 1) json += ",";
  }
  json += "]}";
  return json;
}

