// ── Route handlers ────────────────────────────────────────────────────────────
void handle_root() {
  server.send_P(200, "text/html", HTML);
}

void handle_data() {
  String json = build_json();
  server.send(200, "application/json", json);
}

void handle_not_found() {
  server.send(404, "text/plain", "Not found");
}

// ── Benchmark ────────────────────────────────────────────────────────────────
void benchmark() {
  const int N = 1000;
  float dummy = 0;  

  // std::sin
  uint32_t t0 = micros();
  for (int i = 0; i < N; i++) {
    float x = (float)i / N * 6.2831853f;
    dummy += sinf(x);
  }
  uint32_t t1 = micros();

  // CORDIC lookup
  uint32_t t2 = micros();
  for (int i = 0; i < N; i++) {
    float x = (float)i / N * 6.2831853f;
    dummy += cordic_sin_lookup(x);
  }
  uint32_t t3 = micros();

  Serial.print("sinf: ");
  Serial.println(t1 - t0);
  Serial.print("cordic: ");
  Serial.println(t3 - t2);
  Serial.print("dummy (anti-optimize): ");
  Serial.println(dummy);
  Serial.print("ratio: ");
  Serial.println((float)(t1-t0)/(float)(t3-t2));
}


// ── Setup / Loop ──────────────────────────────────────────────────────────────
void setup() {
  Serial.begin(115200);
  delay(500);

  Serial.println("\nkigu-quant Demo — Rosito Bench");
  Serial.println("Connecting to WiFi...");

  WiFi.begin(WIFI_SSID, WIFI_PASSWORD);
  while (WiFi.status() != WL_CONNECTED) {
    delay(500);
    Serial.print(".");
  }

  Serial.println();
  Serial.print("Connected. IP: ");
  Serial.println(WiFi.localIP());
  Serial.println("Open your browser and navigate to http://" + WiFi.localIP().toString());

  server.on("/",     handle_root);
  server.on("/data", handle_data);
  server.onNotFound(handle_not_found);
  server.begin();

  Serial.println("WebServer started on port 80.");

  benchmark();
}

void loop() {
  server.handleClient();
}
